import{_ as e,c as n,o,a4 as a}from"./chunks/framework.C7hkbLDc.js";const m=JSON.parse('{"title":"1.1 Operation Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"en/2-csharp/1-intro/1.1-permission.md","filePath":"en/2-csharp/1-intro/1.1-permission.md"}'),i={name:"en/2-csharp/1-intro/1.1-permission.md"};function s(r,t,h,d,p,c){return o(),n("div",{"data-pagefind-body":!0},t[0]||(t[0]=[a('<h1 id="1-1" tabindex="-1">1.1 Operation Permissions <a class="header-anchor" href="#1-1" aria-label="Permalink to “1.1 Operation Permissions”">​</a></h1><p>To use the SDK, the host computer must have operation permissions.</p><p>If a teach pendant is plugged into the IRC-I4A-C series control cabinet, you must switch the teach pendant to automatic mode so that the host computer can connect to the control cabinet. After the host computer obtains operation permissions, the teach pendant loses operation permissions. At this time, the PC status light will turn green, and the TP status indicator will not light up. If the teach pendant is in manual mode, permissions cannot be obtained, and the teach pendant has operation permissions.</p><p>If no teach pendant is plugged into the IRC-I4A-C series control cabinet, you can directly connect to the IRC-I4A-C series control cabinet through the host computer to obtain operation permissions.</p><table tabindex="0"><thead><tr><th>System Status Indicators and Buttons</th><th>Function</th></tr></thead><tbody><tr><td>TP Status Light</td><td>When a teach pendant is plugged into the control cabinet, this light turns green; otherwise, it does not light up.</td></tr><tr><td>PC Status Light</td><td>When operating with the virtual teach pendant software Compass, this light turns green; otherwise, it does not light up.</td></tr><tr><td>AUTO Status Light</td><td>When the robot&#39;s operating mode is automatic or neither the teach pendant nor Compass has control, this light turns green; otherwise, it does not light up.</td></tr><tr><td>TP BYPASS Button</td><td>If the robot is in manual mode before unplugging the teach pendant, you can press and hold this button after unplugging the teach pendant to switch the robot to automatic mode.</td></tr></tbody></table>',5)]))}const l=e(i,[["render",s]]);export{m as __pageData,l as default};
